/**
 * @summary Get all public campaigns plus player's private campaigns
 */
export const getGetCampaignsUrl = (params?: GetCampaignsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/campaigns?${stringifiedParams}`
    : `/api/campaigns`;
};

export const getCampaigns = async (
  params?: GetCampaignsParams,
  options?: RequestInit,
): Promise<Campaign[]> => {
  return customFetch<Campaign[]>(getGetCampaignsUrl(params), {
    ...options,
    method: "GET",
  });
};

